 1	import React, { FC } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import ComponentReady from '@kubevirt-utils/components/Charts/ComponentReady/ComponentReady';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 8	import {
 9	  Card,
10	  CardBody,
11	  CardTitle,
12	  DescriptionListTermHelpText,
13	  DescriptionListTermHelpTextButton,
14	  Divider,
15	  Grid,
16	  GridItem,
17	  Popover,
18	  PopoverPosition,
19	} from '@patternfly/react-core';
20	import { isRunning } from '@virtualmachines/utils';
21	
22	import CPUUtil from './components/CPUUtil/CPUUtil';
23	import MemoryUtil from './components/MemoryUtil/MemoryUtil';
24	import NetworkUtil from './components/NetworkUtil/NetworkUtil';
25	import StorageUtil from './components/StorageUtil/StorageUtil';
26	import UtilizationThresholdCharts from './components/UtilizationThresholdCharts';
27	
28	import './virtual-machines-overview-tab-utilization.scss';
29	
30	type VirtualMachinesOverviewTabUtilizationProps = {
31	  pods: K8sResourceCommon[];
32	  vm: V1VirtualMachine;
33	  vmi: V1VirtualMachineInstance;
34	};
35	
36	const VirtualMachinesOverviewTabUtilization: FC<VirtualMachinesOverviewTabUtilizationProps> = ({
37	  pods,
38	  vm,
39	  vmi,
40	}) => {
41	  const { t } = useKubevirtTranslation();
42	
43	  return (
44	    <Card className="VirtualMachinesOverviewTabUtilization--main">
45	      <div className="title">
46	        <CardTitle className="text-muted">
47	          <DescriptionListTermHelpText>
48	            <Popover
49	              bodyContent={
50	                <Trans ns="plugin__kubevirt-plugin" t={t}>
51	                  <div>Donuts chart represent current values.</div>
52	                  <div>Sparkline charts represent data over time</div>
53	                </Trans>
54	              }
55	              position={PopoverPosition?.right}
56	            >
57	              <DescriptionListTermHelpTextButton>
58	                {t('Utilization')}
59	              </DescriptionListTermHelpTextButton>
60	            </Popover>
61	          </DescriptionListTermHelpText>
62	        </CardTitle>
63	      </div>
64	      <Divider />
65	      <CardBody isFilled>
66	        <ComponentReady isReady={isRunning(vm)} text={t('VirtualMachine is not running')}>
67	          <Grid>
68	            <GridItem span={3}>
69	              <CPUUtil pods={pods} vmi={vmi} />
70	            </GridItem>
71	            <GridItem span={3}>
72	              <MemoryUtil vmi={vmi} />
73	            </GridItem>
74	            <GridItem span={3}>
75	              <StorageUtil vmi={vmi} />
76	            </GridItem>
77	            <GridItem span={3}>
78	              <NetworkUtil vmi={vmi} />
79	            </GridItem>
80	            <UtilizationThresholdCharts pods={pods} vmi={vmi} />
81	          </Grid>
82	        </ComponentReady>
83	      </CardBody>
84	    </Card>
85	  );
86	};
87	
88	export default VirtualMachinesOverviewTabUtilization;

